import React, { Component } from "react";
import "./Log.css"
import axios from "axios";
// import categories from './component/categories';

export default class Login extends Component {

    state = {

        username:"",
        password:"",

    };



  handleChange(e){
    this.setState({
     [e.target.name]:e.target.value,
    })
} ;



handleSubmit(e){
    e.preventDefault();
axios.post("http://localhost:5000/login",{ 

    username :this.state.username,
    password:this.state.password,

}).then((res)  => {
console.log(res.data) // array of object
}).catch((err) => { 
console.log(err);

});
}

    render() {
        return (
            <form onSubmit={this.handleSubmit.bind(this)}>
                <h3>Sign In</h3>

                <div className="form-group">
                    <label>Email address</label>
                    <input type="text"    value = {this.state.email} name="username" onChange={this.handleChange.bind(this)} className="form-control" placeholder="Enter username" />
                </div>

                <div className="form-group">
                    <label>Password</label>
                    <input type="password"  value = {this.state.password} name="password" onChange={this.handleChange.bind(this)} className="form-control" placeholder="Enter password" />
                </div>

                <div className="form-group">
                    <div className="custom-control custom-checkbox">
                        <input type="checkbox" className="custom-control-input" id="customCheck1" />
                        <label className="custom-control-label" htmlFor="customCheck1">Remember me</label>
                    </div>
                </div>

                <a href="/"> <button
                    type="submit" className="btn btn-primary btn-block">Submit</button></a>
                <p className="forgot-password text-right">

                    Forgot <a href="/categories">password?</a>
                </p>
            </form>
        );
    }
}
